mapper.select:
SELECT rp.*, sa.area_name, sp.species_name
FROM release_plan rp
LEFT JOIN sea_area sa ON rp.area_id = sa.id
LEFT JOIN species sp ON rp.species_id = sp.id


        AND rp.area_id = #{areaId}


        AND rp.species_id = #{speciesId}


        AND rp.plan_year = #{planYear}


        AND rp.status = #{status}


ORDER BY rp.created_at DESC
